class ConnectionManager:
    def __init__(self):
        self.active_connections: Dict[str, WebSocket] = {}
        self.user_rooms: Dict[str, List[str]] = {}

    async def connect(self, websocket: WebSocket, client_id: str, room_id: str):
        await websocket.accept()
        self.active_connections[client_id] = websocket
        if client_id not in self.user_rooms:
            self.user_rooms[client_id] = []
        self.user_rooms[client_id].append(room_id)

    async def disconnect(self, client_id: str):
        if client_id in self.active_connections:
            del self.active_connections[client_id]
        if client_id in self.user_rooms:
            del self.user_rooms[client_id]

    async def send_personal_message(self, message: dict, client_id: str):
        if client_id in self.active_connections:
            await self.active_connections[client_id].send_json(message)

    async def broadcast_to_room(self, message: dict, room_id: str, exclude: List[str] = []):
        for client_id, websocket in self.active_connections.items():
            if client_id in self.user_rooms and room_id in self.user_rooms[client_id] and client_id not in exclude:
                await websocket.send_json(message)

    def get_room_users(self, room_id: str) -> List[str]:
        users = []
        for client_id, rooms in self.user_rooms.items():
            if room_id in rooms:
                users.append(client_id)
        return users

