@app_celery.task
def merge_results(results: List[List[Any]]) -> Dict[str, Any]:
    """Merge all processed results"""
    flat_results = [item for sublist in results for item in sublist]
    return {
        'total': len(flat_results),
        'sum': sum(flat_results),
        'average': sum(flat_results) / len(flat_results) if flat_results else 0
    }

