class UserServiceServicer(user_service_pb2_grpc.UserServiceServicer):
    def __init__(self):
        self.users = {}  # In-memory storage for demo
        self.jwt_secret = "your-secret-key"

        # Add some test users
        test_user = User(
            user_id="1",
            username="testuser",
            email="test@example.com",
            password_hash="hashed_password"
        )
        self.users["1"] = test_user

    def _get_from_cache(self, key: str):
        """Get data from Redis cache"""
        try:
            data = redis_client.get(key)
            return data.decode('utf-8') if data else None
        except:
            return None

    def _set_to_cache(self, key: str, value: str, ttl: int = 300):
        """Set data to Redis cache"""
        try:
            redis_client.setex(key, ttl, value)
        except:
            pass

    @circuit(failure_threshold=5, recovery_timeout=30)
    def GetUser(self, request, context):
        """Get user by ID"""
        with tracer.start_as_current_span("GetUser"):
            user_id = request.user_id

            # Try cache first
            cache_key = f"user:{user_id}"
            cached_data = self._get_from_cache(cache_key)

            if cached_data:
                # Return cached user
                import json
                user_data = json.loads(cached_data)
                return user_service_pb2.UserResponse(**user_data)

            # Get from storage
            user = self.users.get(user_id)

            if not user:
                context.set_code(grpc.StatusCode.NOT_FOUND)
                context.set_details("User not found")
                return user_service_pb2.UserResponse()

            # Prepare response
            response = user_service_pb2.UserResponse(
                user_id=user.user_id,
                username=user.username,
                email=user.email,
                created_at=user.created_at.isoformat(),
                updated_at=user.updated_at.isoformat()
            )

            # Cache the response
            self._set_to_cache(cache_key, str(response))

            return response

    def CreateUser(self, request, context):
        """Create a new user"""
        with tracer.start_as_current_span("CreateUser"):
            # Check if user exists
            for user in self.users.values():
                if user.username == request.username or user.email == request.email:
                    context.set_code(grpc.StatusCode.ALREADY_EXISTS)
                    context.set_details("Username or email already exists")
                    return user_service_pb2.UserResponse()

            # Create new user
            user_id = str(uuid.uuid4())
            new_user = User(
                user_id=user_id,
                username=request.username,
                email=request.email,
                password_hash=request.password  # In production, hash this
            )

            self.users[user_id] = new_user

            # Invalidate cache
            redis_client.delete("users:list")

            return user_service_pb2.UserResponse(
                user_id=new_user.user_id,
                username=new_user.username,
                email=new_user.email,
                created_at=new_user.created_at.isoformat(),
                updated_at=new_user.updated_at.isoformat()
            )

    def UpdateUser(self, request, context):
        """Update user information"""
        with tracer.start_as_current_span("UpdateUser"):
            user = self.users.get(request.user_id)

            if not user:
                context.set_code(grpc.StatusCode.NOT_FOUND)
                context.set_details("User not found")
                return user_service_pb2.UserResponse()

            # Update fields
            if request.username:
                user.username = request.username
            if request.email:
                user.email = request.email

            user.updated_at = datetime.utcnow()

            # Invalidate cache
            redis_client.delete(f"user:{request.user_id}")
            redis_client.delete("users:list")

            return user_service_pb2.UserResponse(
                user_id=user.user_id,
                username=user.username,
                email=user.email,
                created_at=user.created_at.isoformat(),
                updated_at=user.updated_at.isoformat()
            )

    def DeleteUser(self, request, context):
        """Delete a user"""
        with tracer.start_as_current_span("DeleteUser"):
            if request.user_id not in self.users:
                context.set_code(grpc.StatusCode.NOT_FOUND)
                context.set_details("User not found")
                return user_service_pb2.DeleteResponse(success=False, message="User not found")

            del self.users[request.user_id]

            # Invalidate cache
            redis_client.delete(f"user:{request.user_id}")
            redis_client.delete("users:list")

            return user_service_pb2.DeleteResponse(success=True, message="User deleted")

    def ListUsers(self, request, context):
        """Stream list of users"""
        with tracer.start_as_current_span("ListUsers"):
            # Try cache
            cache_key = f"users:list:{request.page}:{request.limit}"
            cached_data = self._get_from_cache(cache_key)

            if cached_data:
                import json
                users_data = json.loads(cached_data)
                for user_data in users_data:
                    yield user_service_pb2.UserResponse(**user_data)
                return

            # Calculate pagination
            users_list = list(self.users.values())
            start = (request.page - 1) * request.limit
            end = start + request.limit

            paginated_users = users_list[start:end]

            responses = []
            for user in paginated_users:
                response = user_service_pb2.UserResponse(
                    user_id=user.user_id,
                    username=user.username,
                    email=user.email,
                    created_at=user.created_at.isoformat(),
                    updated_at=user.updated_at.isoformat()
                )
                responses.append({
                    'user_id': response.user_id,
                    'username': response.username,
                    'email': response.email,
                    'created_at': response.created_at,
                    'updated_at': response.updated_at
                })
                yield response

            # Cache results
            self._set_to_cache(cache_key, json.dumps(responses))

    def Authenticate(self, request, context):
        """Authenticate user"""
        with tracer.start_as_current_span("Authenticate"):
            # Find user by username
            user = None
            for u in self.users.values():
                if u.username == request.username and u.password_hash == request.password:
                    user = u
