# Service Discovery
class ServiceRegistry:
    def __init__(self):
        self.services = {}

    def register_service(self, service_name: str, host: str, port: int):
        service_key = f"{service_name}:{host}:{port}"
        self.services[service_key] = {
            'name': service_name,
            'host': host,
            'port': port,
            'last_heartbeat': time.time()
        }

        # Also register in Redis for distributed discovery
        redis_client.hset("services", service_key, json.dumps(self.services[service_key]))

    def discover_service(self, service_name: str):
        """Discover service instances with load balancing"""
        instances = []
        for key, service in self.services.items():
            if service['name'] == service_name:
                instances.append(service)

        # Simple round-robin load balancing
        if instances:
            return instances[0]  # In production, implement proper load balancing
        return None

