# Blockchain Core
class Transaction:
    def __init__(self, sender: str, recipient: str, amount: float, signature: str = None):
        self.sender = sender  # Public key of sender
        self.recipient = recipient  # Public key of recipient
        self.amount = amount
        self.timestamp = time.time()
        self.signature = signature

    def to_dict(self) -> Dict[str, Any]:
        return {
            'sender': self.sender,
            'recipient': self.recipient,
            'amount': self.amount,
            'timestamp': self.timestamp
        }

    def sign(self, private_key: ec.EllipticCurvePrivateKey):
        """Sign the transaction"""
        transaction_dict = self.to_dict()
        message = json.dumps(transaction_dict, sort_keys=True).encode()

        signature = private_key.sign(
            message,
            ec.ECDSA(hashes.SHA256())
        )

        self.signature = base64.b64encode(signature).decode('utf-8')

    def is_valid(self) -> bool:
        """Verify transaction signature"""
        if self.sender == "0":  # Mining reward
            return True

        if not self.signature:
            return False

        try:
            # Deserialize public key
            public_key = serialization.load_pem_public_key(
                self.sender.encode(),
                backend=None
            )

            # Verify signature
            transaction_dict = self.to_dict()
            message = json.dumps(transaction_dict, sort_keys=True).encode()
            signature = base64.b64decode(self.signature)

            public_key.verify(
                signature,
                message,
                ec.ECDSA(hashes.SHA256())
            )
            return True
        except (InvalidSignature, ValueError):
            return False

class Block:
    def __init__(self, index: int, transactions: List[Transaction], 
                 timestamp: float, previous_hash: str, nonce: int = 0):
        self.index = index
        self.transactions = transactions
        self.timestamp = timestamp
        self.previous_hash = previous_hash
        self.nonce = nonce
        self.hash = self.calculate_hash()

    def calculate_hash(self) -> str:
        """Calculate SHA-256 hash of the block"""
        block_string = json.dumps({
            'index': self.index,
            'transactions': [tx.to_dict() for tx in self.transactions],
            'timestamp': self.timestamp,
            'previous_hash': self.previous_hash,
            'nonce': self.nonce
        }, sort_keys=True).encode()

        return hashlib.sha256(block_string).hexdigest()

    def mine_block(self, difficulty: int):
        """Mine block with proof-of-work"""
        target = '0' * difficulty

        while self.hash[:difficulty] != target:
            self.nonce += 1
            self.hash = self.calculate_hash()

        logger.info(f"Block mined: {self.hash}")

    def to_dict(self) -> Dict[str, Any]:
        return {
            'index': self.index,
            'transactions': [{
                'sender': tx.sender,
                'recipient': tx.recipient,
                'amount': tx.amount,
                'timestamp': tx.timestamp,
                'signature': tx.signature
            } for tx in self.transactions],
            'timestamp': self.timestamp,
            'previous_hash': self.previous_hash,
            'nonce': self.nonce,
            'hash': self.hash
        }

