            transactions=[],
            timestamp=time.time(),
            previous_hash="0"
        )
        genesis_block.mine_block(self.difficulty)
        self.chain.append(genesis_block)

    def get_latest_block(self) -> Block:
        """Get the latest block in the chain"""
        return self.chain[-1]

    def mine_pending_transactions(self, mining_reward_address: str):
        """Mine pending transactions"""
        # Add mining reward transaction
        reward_tx = Transaction(
            sender="0",  # System
            recipient=mining_reward_address,
            amount=self.mining_reward
        )
        self.pending_transactions.append(reward_tx)

        # Create new block
        block = Block(
            index=len(self.chain),
            transactions=self.pending_transactions,
            timestamp=time.time(),
            previous_hash=self.get_latest_block().hash
        )

        # Mine the block
        block.mine_block(self.difficulty)

        # Add to chain
        self.chain.append(block)

        # Update balances
        for tx in self.pending_transactions:
            if tx.sender != "0":
                self.balances[tx.sender] -= tx.amount
            self.balances[tx.recipient] += tx.amount

        # Reset pending transactions
        self.pending_transactions = []

        # Broadcast new block to network
        self.broadcast_new_block(block)

        return block

    def add_transaction(self, transaction: Transaction) -> bool:
        """Add a new transaction to pending transactions"""
        # Validate transaction
        if not transaction.is_valid():
            return False

        # Check sender balance
        if transaction.sender != "0":  # Not a mining reward
            sender_balance = self.get_balance(transaction.sender)
            if sender_balance < transaction.amount:
                return False

        self.pending_transactions.append(transaction)
        return True

    def get_balance(self, address: str) -> float:
        """Get balance of an address"""
        return self.balances.get(address, 0.0)

    def is_chain_valid(self) -> bool:
        """Validate the entire blockchain"""
        for i in range(1, len(self.chain)):
            current_block = self.chain[i]
            previous_block = self.chain[i-1]

            # Check block hash
            if current_block.hash != current_block.calculate_hash():
                return False

            # Check previous hash reference
            if current_block.previous_hash != previous_block.hash:
                return False

            # Check proof-of-work
            if current_block.hash[:self.difficulty] != '0' * self.difficulty:
                return False

            # Validate all transactions in block
            for tx in current_block.transactions:
                if not tx.is_valid():
                    return False

        return True

    def add_node(self, address: str):
        """Add a new node to the network"""
        self.nodes.add(address)

    def replace_chain(self) -> bool:
        """Replace chain with longest valid chain from network"""
        network = self.nodes
        longest_chain = None
        max_length = len(self.chain)

        for node in network:
            try:
                response = requests.get(f'http://{node}/chain')
                if response.status_code == 200:
                    chain_data = response.json()
                    length = chain_data['length']
                    chain = chain_data['chain']

                    if length > max_length and self.validate_chain(chain):
                        max_length = length
                        longest_chain = chain
            except requests.exceptions.RequestException:
                continue

        if longest_chain:
            self.chain = [Block(**block_data) for block_data in longest_chain]
            return True

        return False

    def validate_chain(self, chain_data: List[Dict]) -> bool:
        """Validate a chain"""
        # Simplified validation
        for i in range(1, len(chain_data)):
            if chain_data[i]['previous_hash'] != chain_data[i-1]['hash']:
                return False
        return True

    def broadcast_new_block(self, block: Block):
        """Broadcast new block to all nodes"""
        for node in self.nodes:
            try:
                requests.post(f'http://{node}/blocks/new', 
                            json=block.to_dict())
            except requests.exceptions.RequestException:
                continue

# Wallet
class Wallet:
    def __init__(self):
        self.private_key = ec.generate_private_key(ec.SECP256K1())
        self.public_key = self.private_key.public_key()
        self.address = self.generate_address()

    def generate_address(self) -> str:
        """Generate wallet address from public key"""
        # Serialize public key
        public_bytes = self.public_key.public_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PublicFormat.SubjectPublicKeyInfo
        )

        # Create address from hash of public key
        address = hashlib.sha256(public_bytes).hexdigest()[:40]
        return address

    def get_public_key_pem(self) -> str:
        """Get public key in PEM format"""
        public_bytes = self.public_key.public_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PublicFormat.SubjectPublicKeyInfo
        )
        return public_bytes.decode('utf-8')

    def create_transaction(self, recipient_address: str, amount: float) -> Transaction:
        """Create a new transaction"""
        transaction = Transaction(
            sender=self.get_public_key_pem(),
            recipient=recipient_address,
            amount=amount
        )

        transaction.sign(self.private_key)
        return transaction

# P2P Network
class P2PNetwork:
    def __init__(self, blockchain: Blockchain, host='0.0.0.0', port=5000):
        self.blockchain = blockchain
        self.host = host
        self.port = port
        self.peers = set()
        self.server_socket = None
        self.running = False

    def start_server(self):
        """Start P2P server"""
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(5)

        self.running = True
        logger.info(f"P2P server started on {self.host}:{self.port}")

        while self.running:
            client_socket, address = self.server_socket.accept()
            client_thread = threading.Thread(
                target=self.handle_client,
                args=(client_socket, address)
            )
            client_thread.start()

    def handle_client(self, client_socket, address):
        """Handle incoming client connections"""
        try:
            data = client_socket.recv(4096)
            if data:
                message = pickle.loads(data)
                self.handle_message(message, address)
        except Exception as e:
            logger.error(f"Error handling client {address}: {e}")
        finally:
            client_socket.close()

    def handle_message(self, message: Dict, address: tuple):
        """Handle different message types"""
        msg_type = message.get('type')

        if msg_type == 'connect':
            # New peer connection
            self.peers.add(address[0])
            logger.info(f"New peer connected: {address[0]}")

            # Send current chain
            self.send_chain(address)

        elif msg_type == 'block':
            # New block received
            block_data = message.get('data')
            block = Block(**block_data)

            # Validate and add block
            latest_block = self.blockchain.get_latest_block()
            if block.previous_hash == latest_block.hash:
                self.blockchain.chain.append(block)
                logger.info(f"New block added from {address[0]}")

                # Forward to other peers
                self.broadcast(message, exclude=address[0])

    def send_chain(self, address: tuple):
        """Send blockchain to peer"""
        chain_data = {
            'type': 'chain',
            'data': [block.to_dict() for block in self.blockchain.chain]
        }

        try:
            peer_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            peer_socket.connect((address[0], self.port))
            peer_socket.send(pickle.dumps(chain_data))
            peer_socket.close()
        except:
            pass

    def broadcast(self, message: Dict, exclude: str = None):
        """Broadcast message to all peers"""
        for peer in self.peers:
            if peer != exclude:
                try:
                    peer_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                    peer_socket.connect((peer, self.port))
                    peer_socket.send(pickle.dumps(message))
                    peer_socket.close()
                except:
                    self.peers.remove(peer)

    def connect_to_peer(self, host: str, port: int):
        """Connect to a new peer"""
        try:
            peer_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            peer_socket.connect((host, port))

            # Send connect message
            connect_msg = {'type': 'connect'}
            peer_socket.send(pickle.dumps(connect_msg))
            peer_socket.close()

            self.peers.add(host)
            logger.info(f"Connected to peer: {host}:{port}")

        except Exception as e:
            logger.error(f"Failed to connect to {host}:{port}: {e}")

    def stop(self):
        """Stop the P2P server"""
        self.running = False
        if self.server_socket:
            self.server_socket.close()

