@app.post("/contract/deploy")
def deploy_contract(code: str, creator: str):
    """Deploy a new smart contract"""
    contract_address = hashlib.sha256(f"{code}{creator}{time.time()}".encode()).hexdigest()[:40]
    contract = SmartContract(contract_address, code, creator)

    # Store contract (in production, use database)
    blockchain.contracts[contract_address] = contract

    return {
        "contract_address": contract_address,
        "message": "Contract deployed successfully"
    }

@app.post("/contract/{address}/execute")
def execute_contract(address: str, function: str, args: List[Any]):
    """Execute a smart contract function"""
    contract = blockchain.contracts.get(address)
    if not contract:
        raise HTTPException(status_code=404, detail="Contract not found")

    result = contract.execute("caller", function, args)
    return {"result": result}

